const raw = $input.item.json.response;
const match = raw.match(/\{[\s\S]*\}/);
if (!match) throw new Error('No JSON in Ollama response');
const parsed = JSON.parse(match[0]);
parsed.next_check_minutes = Math.min(parsed.next_check_minutes || 15, 3);
const sensor = $('MQTT Trigger').item.json;
const weather = $('Get Weather Forecast').item.json;
return [{
  json: {
    soil_moisture: sensor.soil_moisture,
    temperature: sensor.temperature,
    humidity: sensor.humidity,
    rain_detected: sensor.rain_detected || false,
    rain_expected: weather.rain_expected ?? false,
    light_level: sensor.light_level || 500.0,
    last_irrigated_minutes: sensor.last_irrigated_minutes || 60,
    pump_runtime_today: sensor.pump_runtime_today || 0,
    decision: parsed.decision,
    reason: parsed.reason,
    health_score: parsed.health_score || 50.0,
    next_check_minutes: parsed.next_check_minutes,
    urgency: parsed.urgency || 'low'
  }
}];
